// A basic interface
interface User {
  id:        number;
  name:      string;
  email:     string;
}

// Variables, parameters, and return types can be annotated with an interface
function greet(user: User): string {
  return `Hello, ${user.name}`;
}

// Any object that has at least these properties satisfies the interface
const alice: User = { id: 1, name: "Alice", email: "alice@example.com" };
greet(alice); // OK

// Inline object also satisfies it — TypeScript checks the shape, not the origin
greet({ id: 2, name: "Bob", email: "bob@example.com" }); // OK

interface Product {
  id:          number;
  name:        string;
  description?: string;        // optional — may be absent or undefined
  readonly sku: string;        // read-only — cannot be changed after creation
  price:       number;
}

// Optional properties can be omitted
const widget: Product = {
  id:    1,
  name:  "Widget",
  sku:   "WGT-001",
  price: 9.99,
  // description is omitted — valid because it is optional
};

// Readonly prevents mutation
// widget.sku = "WGT-002"; // Error: Cannot assign to 'sku' because it is read-only

// Accessing optional properties safely
function describe(p: Product): string {
  return p.description ?? "No description";
}

// Angular component input — optional with a default
interface ButtonProps {
  label:    string;
  disabled?: boolean;
  variant?:  "primary" | "secondary" | "danger";
}

interface Formatter {
  // Method shorthand — most common
  format(value: number): string;

  // Property with a function type — equivalent for most purposes
  parse: (input: string) => number;

  // Call signature — makes the interface itself callable
  (input: string): string;
}

// Shorthand vs property-function: the key difference is strictFunctionTypes
// With method shorthand, TypeScript is more lenient with parameter types (bivariant).
// With property-function syntax, TypeScript is strict (contravariant parameters).

interface Comparator<T> {
  compare(a: T, b: T): number;  // bivariant under strictFunctionTypes
}

interface StrictComparator<T> {
  compare: (a: T, b: T) => number; // contravariant — stricter
}

// Angular service interface
interface Logger {
  log(message: string, level?: "info" | "warn" | "error"): void;
  clear(): void;
}

// Overloaded method signatures
interface Parser {
  parse(value: string): number;
  parse(value: string, radix: number): number;
}

// String index signature — all values must share the same type
interface StringMap {
  [key: string]: string;
}

const headers: StringMap = {
  "Content-Type": "application/json",
  "Authorization": "Bearer token123",
};
headers["X-Custom"] = "value"; // OK

// Number index signature — accessed with a numeric index (like an array)
interface NumberedList {
  [index: number]: string;
  length: number; // named properties are allowed alongside index signatures
}

// Mixed: named properties + index signature
// Named property type must be assignable to index signature value type
interface FlexRecord {
  id:        number;           // TS requires number to extend unknown
  [key: string]: unknown;      // unknown satisfies all named property types
}

// Angular HTTP response with variable fields
interface ApiResponse {
  status: number;
  message: string;
  [key: string]: unknown; // extra fields allowed
}

// Record<K, V> is generally preferred over index signatures for typed keys
import {} from "@angular/common/http";
type Headers = Record<string, string>; // cleaner than interface with index sig

interface Entity {
  id:        number;
  createdAt: Date;
  updatedAt: Date;
}

interface User extends Entity {
  name:  string;
  email: string;
}

interface Admin extends User {
  role:        "admin" | "superadmin";
  permissions: string[];
}

// Multiple extension — Admin now has all fields from Entity + User + Moderator
interface Moderator extends Entity {
  canDeletePosts: boolean;
}
interface SuperUser extends User, Moderator {
  isSuperUser: true;
}

// Angular-style: extend a base component props interface
interface BaseWidgetProps {
  id?:       string;
  className?: string;
}

interface CardProps extends BaseWidgetProps {
  title: string;
  body:  string;
}

interface AccordionProps extends BaseWidgetProps {
  items: { heading: string; content: string }[];
}

interface Animal {
  name: string;
  speak(): string;
}

interface Domestic {
  owner: string;
}

class Dog implements Animal, Domestic {
  name: string;
  owner: string;

  constructor(name: string, owner: string) {
    this.name  = name;
    this.owner = owner;
  }

  speak(): string {
    return "Woof!";
  }
}

// Angular service implementing a contract
interface UserStore {
  getAll(): Promise<User[]>;
  getById(id: number): Promise<User | null>;
  save(user: User): Promise<User>;
  delete(id: number): Promise<void>;
}

@Injectable({ providedIn: "root" })
class HttpUserStore implements UserStore {
  constructor(private http: HttpClient) {}

  getAll()              { return firstValueFrom(this.http.get<User[]>("/api/users")); }
  getById(id: number)   { return firstValueFrom(this.http.get<User>(`/api/users/${id}`)); }
  save(user: User)      { return firstValueFrom(this.http.put<User>(`/api/users/${user.id}`, user)); }
  delete(id: number)    { return firstValueFrom(this.http.delete<void>(`/api/users/${id}`)); }
}

// Swap the implementation in tests without changing any component code
class InMemoryUserStore implements UserStore {
  private users: User[] = [];
  async getAll()            { return [...this.users]; }
  async getById(id: number) { return this.users.find(u => u.id === id) ?? null; }
  async save(user: User)    { this.users.push(user); return user; }
  async delete(id: number)  { this.users = this.users.filter(u => u.id !== id); }
}

// Same file or different files (e.g., augmenting a library)
interface Window {
  myApp: { version: string };
}

interface Window {
  analytics: { track(event: string): void };
}

// Merged result:
// interface Window {
//   myApp: { version: string };
//   analytics: { track(event: string): void };
//   ...all the original DOM members...
// }

// Module augmentation — extend a third-party library
import "express";

declare module "express" {
  interface Request {
    currentUser?: { id: number; role: string };
  }
}

// Angular: augment environment to add typed feature flags
declare module "@angular/core" {
  interface Environment {
    featureFlags: Record<string, boolean>;
  }
}

// Type alias — declaration merging does NOT work:
// type Point = { x: number };
// type Point = { y: number }; // Error: Duplicate identifier "Point"

interface Point {
  x: number;
  y: number;
}

// Structural match — variable assigned, no error
const p3 = { x: 1, y: 2, z: 3 };
const pt: Point = p3; // OK — p3 has x and y, extra z is allowed via assignment

// Excess property check — object literal triggers error
// const pt2: Point = { x: 1, y: 2, z: 3 }; // Error: Object literal may only specify known properties

// Why? Excess property checks catch typos in object literals
interface Config {
  timeout?: number;
  retries?: number;
}
// const cfg: Config = { timeout: 3000, retires: 3 }; // Error — "retires" is not "retries"

// Workaround 1 — assign to a variable first
const raw = { timeout: 3000, retires: 3 };
const cfg: Config = raw; // No error — structural check only

// Workaround 2 — use a type assertion (avoid in production code)
const cfg2 = { timeout: 3000, retires: 3 } as Config; // Allowed

// Angular component props — excess checks help catch template binding typos
interface TooltipDirectiveInputs {
  appTooltip: string;
  position?: "top" | "bottom" | "left" | "right";
}

// Generic container
interface Box<T> {
  value: T;
  label: string;
}

const numBox: Box<number> = { value: 42, label: "answer" };
const strBox: Box<string> = { value: "hello", label: "greeting" };

// Generic with constraint
interface Repository<T extends { id: number }> {
  findById(id: number): Promise<T | null>;
  findAll(): Promise<T[]>;
  save(entity: T): Promise<T>;
  delete(id: number): Promise<void>;
}

interface User { id: number; name: string; email: string }
interface Post { id: number; title: string; body: string }

// Concrete implementations — type parameter supplies the entity shape
@Injectable({ providedIn: "root" })
class UserRepository implements Repository<User> {
  constructor(private http: HttpClient) {}
  findById(id: number) { return firstValueFrom(this.http.get<User>(`/api/users/${id}`)); }
  findAll()            { return firstValueFrom(this.http.get<User[]>("/api/users")); }
  save(user: User)     { return firstValueFrom(this.http.put<User>(`/api/users/${user.id}`, user)); }
  delete(id: number)   { return firstValueFrom(this.http.delete<void>(`/api/users/${id}`)); }
}

// Generic response wrapper
interface PagedResult<T> {
  items: T[];
  total: number;
  page:  number;
  size:  number;
}

// Generic event emitter interface
interface TypedEventEmitter<Events extends Record<string, unknown>> {
  on<K extends keyof Events>(event: K, handler: (payload: Events[K]) => void): void;
  emit<K extends keyof Events>(event: K, payload: Events[K]): void;
  off<K extends keyof Events>(event: K, handler: (payload: Events[K]) => void): void;
}

// Callable interface — the interface itself is a function
interface Greeter {
  (name: string): string;  // call signature
  prefix: string;          // also has properties
}

// Implementing a callable interface
const greeter: Greeter = (name) => `${greeter.prefix} ${name}`;
greeter.prefix = "Hello,";

console.log(greeter("Alice")); // "Hello, Alice"

// Constructable interface — describes a constructor (new keyword)
interface ClockConstructor {
  new (hour: number, minute: number): ClockInterface;
}

interface ClockInterface {
  tick(): void;
}

function createClock(
  ctor: ClockConstructor,
  hour: number,
  minute: number
): ClockInterface {
  return new ctor(hour, minute);
}

class DigitalClock implements ClockInterface {
  constructor(h: number, m: number) {}
  tick() { console.log("beep"); }
}

const clock = createClock(DigitalClock, 12, 17);

// Angular: InjectionToken uses a construct signature internally
// The factory function passed to useFactory satisfies a callable interface

// Interface — type contract only
interface Logger {
  log(message: string, level?: string): void;
}

// Abstract class — provides default implementation
abstract class BaseLogger {
  abstract log(message: string, level?: string): void;

  // Default implementation available to all subclasses
  logError(message: string): void {
    this.log(message, "error");
  }
}

class ConsoleLogger extends BaseLogger {
  log(message: string, level = "info"): void {
    console[level as "log"](message);
  }
}

// Angular DI — interface cannot be an injection token
// interface Logger { log(msg: string): void } // erasable
// providers: [{ provide: Logger, useClass: ConsoleLogger }] // Error at runtime

// Abstract class works as a DI token (it exists at runtime)
abstract class LoggerToken { abstract log(msg: string): void }
// providers: [{ provide: LoggerToken, useClass: ConsoleLogger }] // OK

import { CanActivateFn, ActivatedRouteSnapshot, RouterStateSnapshot } from "@angular/router";

// Describe the data attached to routes
interface RouteMeta {
  title:       string;
  roles?:      string[];
  breadcrumb?: string;
}

// Use the interface in a typed guard
export const authGuard: CanActivateFn = (
  route: ActivatedRouteSnapshot,
  state: RouterStateSnapshot
) => {
  const meta = route.data as RouteMeta;
  const requiredRoles = meta.roles ?? [];
  // check roles against current user
  return requiredRoles.length === 0 || hasAllRoles(requiredRoles);
};

// Route config
const routes = [
  {
    path: "admin",
    canActivate: [authGuard],
    data: { title: "Admin", roles: ["admin"] } satisfies RouteMeta,
  },
];

import { signal, computed, Signal } from "@angular/core";

// Interface for a typed store slice
interface CartStore {
  items:        Signal<CartItem[]>;
  total:        Signal<number>;
  addItem(item: CartItem): void;
  removeItem(id: number): void;
  clear(): void;
}

// Implementation using Angular signals
function createCartStore(): CartStore {
  const items = signal<CartItem[]>([]);
  const total = computed(() =>
    items().reduce((sum, i) => sum + i.price * i.quantity, 0)
  );

  return {
    items,
    total,
    addItem(item) { items.update(current => [...current, item]); },
    removeItem(id) { items.update(current => current.filter(i => i.id !== id)); },
    clear() { items.set([]); },
  };
}

// In a test, replace with a stub that implements the same interface
const mockCart: CartStore = {
  items:      signal([]),
  total:      signal(0),
  addItem:    () => {},
  removeItem: () => {},
  clear:      () => {},
};
